head.script:
scwin.initData = {
	"isValidate" : false,
	"isSaveProcess" : false,
	"acbMappingCdObj" : {
		"elcpwstnNm" : "cmmnCd"
	},
	"acbMappingNmObj" : {
	},
	"valInfo" : [
		{id : "cerDelngDe", minLength : 8, maxByteLength : 8, mandatory : true, number : true, dateFunc : ecsLib.validatorYearMonthDate},
		{id : "elcpwstnNm", maxLength : 40, mandatory : true},
		{id : "cerDelngDivNm", maxByteLength : 40, mandatory : true},
		{id : "itemNm", maxByteLength : 1000, mandatory : true},
		{id : "cerDelngUpc", maxByteLength : 13, mandatory : true, number : true},
		{id : "cerDelngQy", maxByteLength : 22, mandatory : true, number : true},
		{id : "cerAmt", maxByteLength : 15, number : true},
		{id : "mrktDivNm", maxByteLength : 40},
		{id : "rmCtnt", maxByteLength : 4000}
	]
}

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSCL2300000", {"initScreenCallback" : scwin.searchDatas});
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 조회조건 설정
	scwin.initSearchParam();
	// 화면 데이터 조회
	scwin.btnInqire_onclick();
};

/**
 * 조회조건 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initSearchParam = function() {
	dmaSearchParam.set("strtDt", utilLib.getCurrentDate("yyyy"));
	dmaSearchParam.set("elcpwstnCd", "ALL");
};

/**
 * 조회조건에 맞게 data를 조회한다.
 * @param
 * @return
 */
scwin.btnInqire_onclick = function() {
	var strtDate = dmaSearchParam.get("strtDt");
	var elcpwstnCd = dmaSearchParam.get("elcpwstnCd");

	if (String(strtDate).length != 4) {
		// 조회기간이 올바르지 않습니다.
		alert(utilLib.getMessage("ECS.INFO.00011")[0]);
		return;
	}

	var queryString = `?strtDt=${strtDate}`;
	queryString += `&ecsElcpwstnDivCd=${elcpwstnCd}`;

	var option = {
		action : "cl/cerexcclc/retrieve-cer-excclc.do"
			+ queryString,
		method : "get",
		resData : dltCerExcclcList,
		success : "scwin.inqireCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 조회 CallBack 실행한다.
 * @param <Object> resBody
 * @return
 */
scwin.inqireCallback = function(resBody) {
	spnTotalRow.setValue(dltCerExcclcList.getRowCount());
	var mandatoryList = scwin.initData.valInfo.filter(obj => obj.mandatory);
	for (var i = 0; i < dltCerExcclcList.getRowCount(); i++) {
		mandatoryList.forEach(obj => {
			grdCerExcclcList.setCellReadOnly(i, obj.id, true);
		});
	}
	scwin.initData.isValidate = false;
};

/**
 * 그리드뷰 행을 추가한다.
 * @param
 * @return
 */
scwin.btnAddRow_onclick = function() {
	var newIndex = dltCerExcclcList.insertRow();

	grdCerExcclcList.setFocusedCell(newIndex, "elcpwstnNm", true);
};

/**
 * 그리드뷰 행을 삭제한다.
 * @param
 * @return
 */
scwin.btnDelRow_onclick = function() {
	var rowIndexList = grdCerExcclcList.getAllFocusedRowIndex();

	dltCerExcclcList.removeRows(rowIndexList);
};

/**
 * 그리드뷰의 내용을 검증한다.
 * @param
 * @return
 */
scwin.btnValidate_onclick = function(confirmValue) {
	if (confirmValue == true || confirmValue == undefined) {
		if (dltCerExcclcList.getModifiedData() == "") {
			// 처리할 데이터가 없습니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
			return;
		}

		if (utilLib.validateGridView(grdCerExcclcList, scwin.initData.valInfo)) {
			var columnList = scwin.initData.valInfo.filter(obj => obj.mandatory).flatMap(obj => obj.id.replace("elcpwstnNm", "ecsElcpwstnDivCd"));
			if (ecsLib.gridViewPkDuplicationCheck(grdCerExcclcList, dltCerExcclcList, columnList)) {
				// 중복 데이터가 있습니다.
				return;
			}

			if (ecsLib.validateGridViewAcb(grdCerExcclcList, dltAutoCondition1, scwin.initData.acbMappingCdObj, scwin.initData.acbMappingNmObj)) {
				// 해당하는 {컬럼명}이(가) 존재하지 않습니다.
				return;
			}
			scwin.initData.isValidate = true;
			if (scwin.initData.isSaveProcess) {
				scwin.initData.isSaveProcess = false;
				scwin.btnSave_onclick();
			} else {
				// 데이터 검증이 완료되었습니다.
				comLib.alert($p, utilLib.getMessage("ECS.INFO.00102"));
			}
		}
	} else {
		scwin.initData.isSaveProcess = false;
	}
};

/**
 * 그리드뷰의 내용을 수정/저장한다.
 * @param
 * @return
 */
scwin.btnSave_onclick = function() {
	scwin.initData.isSaveProcess = false;
	if (dltCerExcclcList.getModifiedData() == "") {
		// 처리할 데이터가 없습니다.
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
		return;
	}

	if (scwin.initData.isValidate) {
		var addCount = 0;
		var modifyCount = 0;
		var delCount = 0;
		dltCerExcclcList.getModifiedJSON().forEach(obj => {
			var rowStatus = obj.rowStatus;
			switch(rowStatus) {
				case "C":
					// 추가
					addCount++;
					break;
				case "U":
					// 수정
					modifyCount++;
					break;
				case "E":
					// 삭제
					delCount++;
					break;
				default:
					break;
			}
		});
		var extendMsg = ecsLib.extendCustomSaveMsg(addCount, modifyCount, delCount);
		// 변경된 내역이 있습니다.\n저장 하시겠습니까? \n수정사유를 입력하세요.
		ecsLib.saveRsn($p, `${dltCerExcclcList.getID()}.updtRsn`, utilLib.getMessage("SCM.INFO.00239")[0] + extendMsg, "scwin.saveConfirmCallback");
	} else {
		scwin.initData.isSaveProcess = true;
		// 데이터 검증 후 저장 가능합니다.\n검증하시겠습니까?
		comLib.confirm($p, utilLib.getMessage("ECS.INFO.00101"), "scwin.btnValidate_onclick", true);
		return;
	}
};

/**
 * 수정/저장 ComfirmCallBack 실행한다.
 * @param
 * @return
 */
scwin.saveConfirmCallback = function() {
	var requestData = {};
	requestData.dltCerExcclcList = dltCerExcclcList.getModifiedJSON();

	var option = {
		action : "cl/cerexcclc/process-cer-excclc-snpw.do",
		reqData : requestData,
		success : "scwin.saveConfirmSuccessCallback",
		savedToken : true,
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 수정/저장 CallBack 실행한다.
 * @param <Object> resBody
 * @return
 */
scwin.saveConfirmSuccessCallback = function(resBody) {
	comLib.alert($p, resBody.message.code_name);

	scwin.btnInqire_onclick();
};

/**
 * 작업중이던 내용을 취소한다.
 * @param
 * @return
 */
scwin.btnCancl_onclick = function() {
	scwin.btnInqire_onclick();
};

/**
 * 화면목록에서 선택한 버튼권한을 삭제한다.
 * @param
 * @return
 */
scwin.btnDel_onclick = function() {
	if (dltCerExcclcList.getModifiedData() != "") {
		comLib.removeGridView(grdCerExcclcList);

		// 삭제하시겠습니까?
		comLib.confirm($p, utilLib.getMessage("SCM.INFO.00251"), "scwin.saveConfirmCallback");
	} else {
		// 삭제할 자료를 선택한 후 처리하시기 바랍니다.
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00252"));
	}
};

/**
 * 데이터컬렉션의 추가/변경/삭제 시 이벤트
 * @param
 * @return
 */
scwin.dltCerExcclcList_ondatachange = function(info) {
	scwin.initData.isValidate = false;
};

/**
 * 조회박스 선택별 값을 세팅한다.
 * @param
 * @return
 */
scwin.acbElcpwstn_onviewchange = function(info) {
	dmaSearchParam.set("elcpwstnCd", info.newValue);
};

scwin.grdCerExcclcList_onafteredit = function(row,col,value) {
	ecsLib.updateGridViewFontColor(grdCerExcclcList, row, col);
};

//============================================================================================
// 엑셀
//============================================================================================
/**
 * 그리드의 내용을 엑셀로 다운로드 한다.
 * @return
 */
scwin.btnDownExcel_onclick = function() {
	var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
	var subTitleNm = spnSubTitle.getValue();
	// 엑셀 내부 타이틀 추가_240105
	var infoArr = [];
	var infoObj = {
		rowIndex 	: 0,
		colIndex 	: 0,
		rowSpan 	: 0,
		colSpan 	: 9,
		text 		: `${menuNm}_` + `${subTitleNm}`,
		textAlign 	: "left"
	};
	infoArr.push(infoObj);

	// 데이터가 없어도 탬플릿만 다운받을 수 있게 comLib.downloadExcel 말고 grdID.advancedExcelDownload 적용_231113
	options = {
		fileName : `${menuNm}_` + `${subTitleNm}.xlsx`,
		type : 1,
		autoSizeColumn : true,
		startRowIndex : 1,
		startColumnIndex : 0,
		useDataFormat: true,
		applyDataFormat : true,
		rowHeight : 40,
		useStyle: true,
		hidden: 1
	}
	grdCerExcclcList.advancedExcelDownload(options, infoArr);
};

/**
 * 엑셀의 내용을 그리드에 업로드 한다.
 * @return
 */
scwin.btnUploadExcel_onclick = function() {
	var options = {
		type : 1,
		headerExist : 1,
		startRowIndex : 1,
		startColumnIndex : 0,
		endColumnIndex : 8,
		sheetNo : 0,
		append : 0,
		status: "C",
		useMaxByteLength : true
	};
	comLib.uploadExcel(grdCerExcclcList, options);
};

/**
 * 엑셀 내용을 그리드에 저장한다.
 * @return
 */
scwin.grdCerExcclcList_onfilereadend = function(value) {
	var dltData = dltCerExcclcList.getAllJSON();
	var dltAuto1 = dltAutoCondition1.getAllJSON();
	// set JSON
	for (var idx = 0; idx < dltData.length; idx++) {
		var elcpwstnNm = (dltAuto1.find(obj => obj.cmmnCd == dltData[idx].elcpwstnNm) || 0).cmmnCd;
		dltCerExcclcList.setCellData(idx, "elcpwstnNm", elcpwstnNm);
		// 엑셀에서 빈값으로 넣을경우 0으로 나오는 걸 ""으로 수정_231208
			for (var key in dltData) {
				var innerObj = dltData[key];
				for (var innerKey in innerObj) {
					if (innerKey.startsWith("cerDelngUpc") && innerObj[innerKey] === "0") {
						dltData[key][innerKey] = "";
					} else if (innerKey.startsWith("cerDelngQy") && innerObj[innerKey] === "0") {
						dltData[key][innerKey] = "";
					}
				}
				dltCerExcclcList.setJSON(dltData);
			}
			// rowStatus 상태값 변경(setJSON을 하면 options의 status 설정이 적용 안됨)_231208
			dltCerExcclcList.modifyRowStatus(idx, "C");
	}
};

/**
 * 단가, 거래수량 수정시 거래금액을 계산한다.
 * @return
 */
scwin.grdCerExcclcList_onviewchange = function(info) {
	var row = info.rowIndex;
	var col = info.colIndex;
	var value = info.newValue;
	var colId = grdCerExcclcList.getColumnID(col);

	if (colId == "cerDelngUpc" || colId == "cerDelngQy") {
		var data = dltCerExcclcList.getRowJSON(row);
		var cerDelngUpc = data.cerDelngUpc;
		var cerDelngQy = data.cerDelngQy;
		data.cerAmt = cerDelngUpc * cerDelngQy;
		dltCerExcclcList.setRowJSON(row, data, true);
	}
};
